"Denominator Exception" AS (
SELECT p.patient_id FROM _patients AS p WHERE FALSE
),
"Has Qualifying Encounter" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Encounter: Office Visit" AS OfficeVisit WHERE OfficeVisit.patient_id = p.patient_id AND intervalIncludes(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE), fhirpath_text(OfficeVisit.resource, 'period')) AND fhirpath_text(OfficeVisit.resource, 'status') = 'finished')
),
"Prostate Cancer Diagnosis" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Condition: Prostate Cancer (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Prostate Cancer (qicore-condition-encounter-diagnosis)") AS ProstateCancer WHERE intervalOverlaps(CASE WHEN fhirpath_text(ProstateCancer.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ProstateCancer.resource, 'onsetDateTime'), fhirpath_text(ProstateCancer.resource, 'onsetPeriod.start'), fhirpath_text(ProstateCancer.resource, 'recordedDate')), fhirpath_text(ProstateCancer.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ProstateCancer.resource, 'onsetDateTime'), fhirpath_text(ProstateCancer.resource, 'onsetPeriod.start'), fhirpath_text(ProstateCancer.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ProstateCancer.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ProstateCancer.resource, 'onsetDateTime'), fhirpath_text(ProstateCancer.resource, 'onsetPeriod.start'), fhirpath_text(ProstateCancer.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ProstateCancer.resource, 'onsetDateTime'), fhirpath_text(ProstateCancer.resource, 'onsetPeriod.start'), fhirpath_text(ProstateCancer.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AND fhirpath_bool(ProstateCancer.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') AND fhirpath_bool(ProstateCancer.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()')
),
"First ADT in 3 Months Before to 9 Months After Start of Measurement Period" AS (
SELECT p.patient_id, (SELECT resource FROM ((SELECT patient_id, value AS resource FROM "Androgen Deprivation Therapy for Urology Care Medication Active Start Dates") UNION (SELECT patient_id, value AS resource FROM "Androgen Deprivation Therapy for Urology Care Medication Order Start Dates")) AS ADTDateTime WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Prostate Cancer Diagnosis") AS ProstateCancer WHERE CAST(ADTDateTime.resource AS DATE) >= CAST(intervalStart(CASE WHEN fhirpath_text(ProstateCancer.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ProstateCancer.resource, 'onsetDateTime'), fhirpath_text(ProstateCancer.resource, 'onsetPeriod.start'), fhirpath_text(ProstateCancer.resource, 'recordedDate')), fhirpath_text(ProstateCancer.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ProstateCancer.resource, 'onsetDateTime'), fhirpath_text(ProstateCancer.resource, 'onsetPeriod.start'), fhirpath_text(ProstateCancer.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ProstateCancer.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ProstateCancer.resource, 'onsetDateTime'), fhirpath_text(ProstateCancer.resource, 'onsetPeriod.start'), fhirpath_text(ProstateCancer.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ProstateCancer.resource, 'onsetDateTime'), fhirpath_text(ProstateCancer.resource, 'onsetPeriod.start'), fhirpath_text(ProstateCancer.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) AND CAST(ADTDateTime.resource AS DATE) <= COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(ProstateCancer.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ProstateCancer.resource, 'onsetDateTime'), fhirpath_text(ProstateCancer.resource, 'onsetPeriod.start'), fhirpath_text(ProstateCancer.resource, 'recordedDate')), fhirpath_text(ProstateCancer.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ProstateCancer.resource, 'onsetDateTime'), fhirpath_text(ProstateCancer.resource, 'onsetPeriod.start'), fhirpath_text(ProstateCancer.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ProstateCancer.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ProstateCancer.resource, 'onsetDateTime'), fhirpath_text(ProstateCancer.resource, 'onsetPeriod.start'), fhirpath_text(ProstateCancer.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ProstateCancer.resource, 'onsetDateTime'), fhirpath_text(ProstateCancer.resource, 'onsetPeriod.start'), fhirpath_text(ProstateCancer.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) AND CAST(ADTDateTime.resource AS DATE) >= CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 3.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS DATE) AND CAST(ADTDateTime.resource AS DATE) <= CAST(dateAddQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 9.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS DATE) AND ProstateCancer.patient_id = ADTDateTime.patient_id) AND ADTDateTime.patient_id = p.patient_id ORDER BY resource ASC NULLS LAST LIMIT 1) AS resource FROM _patients AS p
),
"Order for 12 Months of ADT in 3 Months Before to 9 Months After Start of Measurement Period" AS (
SELECT * FROM "ServiceRequest: Injection of leuprolide acetate for twelve month period (regime/therapy)" AS OrderTwelveMonthADT WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "First ADT in 3 Months Before to 9 Months After Start of Measurement Period") AS FirstADTMP WHERE CAST(fhirpath_text(OrderTwelveMonthADT.resource, 'authoredOn') AS TIMESTAMP) >= CAST(FirstADTMP.resource AS DATE) AND CAST(fhirpath_text(OrderTwelveMonthADT.resource, 'authoredOn') AS DATE) >= CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 3.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS DATE) AND CAST(fhirpath_text(OrderTwelveMonthADT.resource, 'authoredOn') AS DATE) <= CAST(dateAddQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 9.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS DATE) AND array_contains(['active', 'completed'], fhirpath_text(OrderTwelveMonthADT.resource, 'status')) AND fhirpath_text(OrderTwelveMonthADT.resource, 'intent') = 'order' AND fhirpath_text(OrderTwelveMonthADT.resource, 'doNotPerform') IS NOT TRUE AND FirstADTMP.patient_id = OrderTwelveMonthADT.patient_id)
),
"Has Baseline DEXA Scan Two Years Prior to the Start of or Less than Three Months After the Start of ADT" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM ((SELECT patient_id, resource FROM "ServiceRequest: DEXA Bone Density for Urology Care" AS DEXAOrdered WHERE array_contains(['active', 'completed'], fhirpath_text(DEXAOrdered.resource, 'status')) AND fhirpath_text(DEXAOrdered.resource, 'intent') = 'order' AND fhirpath_text(DEXAOrdered.resource, 'doNotPerform') IS NOT TRUE AND EXISTS (SELECT 1 FROM (SELECT * FROM "Order for 12 Months of ADT in 3 Months Before to 9 Months After Start of Measurement Period") AS OrderTwelveMonthsADT WHERE (CAST(fhirpath_text(OrderTwelveMonthsADT.resource, 'authoredOn') AS DATE) <= CAST(fhirpath_text(DEXAOrdered.resource, 'authoredOn') AS DATE) AND CAST(fhirpath_text(DEXAOrdered.resource, 'authoredOn') AS DATE) <= CAST(fhirpath_text(OrderTwelveMonthsADT.resource, 'authoredOn') AS DATE) + INTERVAL '3 month' OR CAST(fhirpath_text(OrderTwelveMonthsADT.resource, 'authoredOn') AS DATE) - INTERVAL '2 year' <= CAST(fhirpath_text(DEXAOrdered.resource, 'authoredOn') AS DATE) AND CAST(fhirpath_text(DEXAOrdered.resource, 'authoredOn') AS DATE) < CAST(fhirpath_text(OrderTwelveMonthsADT.resource, 'authoredOn') AS DATE)) AND OrderTwelveMonthsADT.patient_id = DEXAOrdered.patient_id)) UNION (SELECT patient_id, resource FROM "Observation: DEXA Bone Density for Urology Care" AS DEXAPerformed WHERE array_contains(['final', 'amended', 'corrected'], fhirpath_text(DEXAPerformed.resource, 'status')) AND EXISTS (SELECT 1 FROM (SELECT * FROM "Order for 12 Months of ADT in 3 Months Before to 9 Months After Start of Measurement Period") AS OrderTwelveMonthsADT WHERE (CAST(fhirpath_text(OrderTwelveMonthsADT.resource, 'authoredOn') AS DATE) <= CAST(intervalStart(CASE WHEN fhirpath_text(DEXAPerformed.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DEXAPerformed.resource, 'effective')), '{') THEN fhirpath_text(DEXAPerformed.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DEXAPerformed.resource, 'effective'), fhirpath_text(DEXAPerformed.resource, 'effective'), TRUE, TRUE) END) AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(DEXAPerformed.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DEXAPerformed.resource, 'effective')), '{') THEN fhirpath_text(DEXAPerformed.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DEXAPerformed.resource, 'effective'), fhirpath_text(DEXAPerformed.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= CAST(fhirpath_text(OrderTwelveMonthsADT.resource, 'authoredOn') AS DATE) + INTERVAL '3 month' OR CAST(fhirpath_text(OrderTwelveMonthsADT.resource, 'authoredOn') AS DATE) - INTERVAL '2 year' <= CAST(intervalStart(CASE WHEN fhirpath_text(DEXAPerformed.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DEXAPerformed.resource, 'effective')), '{') THEN fhirpath_text(DEXAPerformed.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DEXAPerformed.resource, 'effective'), fhirpath_text(DEXAPerformed.resource, 'effective'), TRUE, TRUE) END) AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(DEXAPerformed.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DEXAPerformed.resource, 'effective')), '{') THEN fhirpath_text(DEXAPerformed.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DEXAPerformed.resource, 'effective'), fhirpath_text(DEXAPerformed.resource, 'effective'), TRUE, TRUE) END) AS DATE) < CAST(fhirpath_text(OrderTwelveMonthsADT.resource, 'authoredOn') AS DATE)) AND OrderTwelveMonthsADT.patient_id = DEXAPerformed.patient_id))) AS _u WHERE _u.patient_id = p.patient_id)
),
"Initial Population" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Qualifying Encounter" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "Order for 12 Months of ADT in 3 Months Before to 9 Months After Start of Measurement Period" AS sub WHERE sub.patient_id = p.patient_id)
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
"No Bone Density Scan Ordered Due to Patient Refusal" AS (
SELECT * FROM "ServiceRequest: DEXA Bone Density for Urology Care (servicenotrequested)" AS DEXANotOrdered WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Order for 12 Months of ADT in 3 Months Before to 9 Months After Start of Measurement Period") AS OrderTwelveMonthsADT WHERE CAST(fhirpath_text(OrderTwelveMonthsADT.resource, 'authoredOn') AS DATE) <= CAST(fhirpath_text(DEXANotOrdered.resource, 'authoredOn') AS DATE) AND CAST(fhirpath_text(DEXANotOrdered.resource, 'authoredOn') AS DATE) <= CAST(fhirpath_text(OrderTwelveMonthsADT.resource, 'authoredOn') AS DATE) + INTERVAL '3 month' AND in_valueset(DEXANotOrdered.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-doNotPerformReason'').valueCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1582') AND OrderTwelveMonthsADT.patient_id = DEXANotOrdered.patient_id)
),
"No Bone Density Scan Performed Due to Patient Refusal" AS (
SELECT * FROM "Observation: DEXA Bone Density for Urology Care (observationcancelled)" AS DEXANotPerformed WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Order for 12 Months of ADT in 3 Months Before to 9 Months After Start of Measurement Period") AS OrderTwelveMonthsADT WHERE CAST(fhirpath_text(OrderTwelveMonthsADT.resource, 'authoredOn') AS DATE) <= CAST(fhirpath_text(DEXANotPerformed.resource, 'issued') AS DATE) AND CAST(fhirpath_text(DEXANotPerformed.resource, 'issued') AS DATE) <= CAST(fhirpath_text(OrderTwelveMonthsADT.resource, 'authoredOn') AS DATE) + INTERVAL '3 month' AND in_valueset(DEXANotPerformed.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-notDoneReason'').valueCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1582') AND OrderTwelveMonthsADT.patient_id = DEXANotPerformed.patient_id)
),
"Numerator" AS (
SELECT * FROM "Has Baseline DEXA Scan Two Years Prior to the Start of or Less than Three Months After the Start of ADT"
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exception".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exception", (SELECT CASE WHEN "Numerator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exception" ON p.patient_id = "Denominator Exception".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
